Here's the full implementation:

**XAML — wrap `CollectionView` in `RefreshView` for pull-to-refresh:**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemListPage"
             x:DataType="vm:ItemListViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}"
                        EmptyView="No items found.">

            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>

            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*">
                        <VisualStateManager.VisualStateGroups>
                            <VisualStateGroup Name="CommonStates">
                                <VisualState Name="Normal">
                                    <VisualState.Setters>
                                        <Setter Property="BackgroundColor" Value="Transparent" />
                                    </VisualState.Setters>
                                </VisualState>
                                <VisualState Name="Selected">
                                    <VisualState.Setters>
                                        <Setter Property="BackgroundColor" Value="{StaticResource Primary}" />
                                    </VisualState.Setters>
                                </VisualState>
                            </VisualStateGroup>
                        </VisualStateManager.VisualStateGroups>

                        <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                        <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>

        </CollectionView>
    </RefreshView>
</ContentPage>
```

**ViewModel — using CommunityToolkit.Mvvm:**

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

namespace MyApp.ViewModels;

public partial class ItemListViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    public ItemListViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={CurrentItem.Id}");

        // Clear selection so the same item can be re-selected later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var freshItems = await _itemService.GetItemsAsync();
            Items.Clear();
            foreach (var item in freshItems)
                Items.Add(item);
        }
        finally
        {
            // Must set to false or the spinner stays visible
            IsRefreshing = false;
        }
    }
}
```

**Key binding relationships:**

| XAML Property | ViewModel Property | Why |
|---|---|---|
| `ItemsSource` | `ObservableCollection<Item> Items` | Auto-updates UI on add/remove |
| `SelectedItem` (TwoWay) | `CurrentItem` | VM reads which item was tapped |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Triggers navigation logic |
| `RefreshView.IsRefreshing` | `IsRefreshing` | Controls the spinner — **must be set `false` when done** |
| `RefreshView.Command` | `RefreshCommand` | Fires your API reload |

**Important details:**

- **`x:DataType`** is set on both the page (→ViewModel) and the `DataTemplate` (→ Model) for compiled bindings.
- **`MeasureFirstItem`** improves scroll performance when items are uniform height.
- **`CurrentItem = null`** after navigation lets the user re-select the same item.
- **`IsRefreshing = false`** in a `finally` block ensures the spinner always stops, even on error.
- **Never use `ViewCell`** — the `Grid` root in the template is correct for CollectionView.
